compliant:
class Base {
public:
    virtual void method() {}
};

// Compliant - regular inheritance
class Derived : public Base {
public:
    void method() override {}
};

// Compliant - use composition instead of virtual inheritance
class CompositionApproach {
public:
    void useBase() { base.method(); }
private:
    Base base; // Composition
};

// Compliant - interface-based design
class IInterface {
public:
    virtual ~IInterface() = default;
    virtual void method() = 0;
};

class Implementation : public IInterface {
public:
    void method() override {}
};
